    public Object parseMarket(Object market)
    {
        //
        //   {
        //      "base":{
        //         "code":"BTC",
        //         "precision":"5"
        //      },
        //      "quote":{
        //         "code":"USDC",
        //         "precision":"2"
        //      },
        //      "amount_precision":"5",
        //      "market_precision":"2",
        //      "min_size":"10.0",
        //      "min_price":"1000",
        //      "max_price":"10000000",
        //      "id":"BTC_USDC",
        //      "type":"SPOT",
        //      "state":"ACTIVE"
        //   }
        //
        //
        //  {
        //      "base": {
        //          "code": "BTC",
        //          "precision": 5
        //      },
        //      "quote": {
        //          "code": "EUR",
        //          "precision": 2
        //      },
        //      "amount_precision": 5,
        //      "market_precision": 2,
        //      "min_size": "10.0",
        //      "min_price": "1000",
        //      "max_price": "10000000",
        //      "id": "BTC_EUR_P",
        //      "type": "PERP",
        //      "state": "ACTIVE"
        //  }
        //
        Object baseAsset = this.safeDict(market, "base", new java.util.HashMap<String, Object>() {{}});
        Object quoteAsset = this.safeDict(market, "quote", new java.util.HashMap<String, Object>() {{}});
        Object baseId = this.safeString(baseAsset, "code");
        Object quoteId = this.safeString(quoteAsset, "code");
        Object id = this.safeString(market, "id");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object state = this.safeString(market, "state");
        Object type = this.safeString(market, "type");
        Object isPerp = Helpers.isEqual(type, "PERP");
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        if (Helpers.isTrue(isPerp))
        {
            symbol = Helpers.add(Helpers.add(symbol, ":"), quote);
        }
        final Object finalSymbol = symbol;
        final Object finalBase = base;
        final Object finalState = state;
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", finalSymbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", ((Helpers.isTrue(isPerp))) ? quote : null );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", ((Helpers.isTrue(isPerp))) ? quoteId : null );
            put( "type", ((Helpers.isTrue(isPerp))) ? "swap" : "spot" );
            put( "spot", !Helpers.isTrue(isPerp) );
            put( "margin", false );
            put( "swap", isPerp );
            put( "future", false );
            put( "option", false );
            put( "active", (Helpers.isEqual(finalState, "ACTIVE")) );
            put( "contract", isPerp );
            put( "linear", ((Helpers.isTrue(isPerp))) ? true : null );
            put( "inverse", ((Helpers.isTrue(isPerp))) ? false : null );
            put( "contractSize", ((Helpers.isTrue(isPerp))) ? OnetradingCore.this.parseNumber("1") : null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", OnetradingCore.this.parseNumber(OnetradingCore.this.parsePrecision(OnetradingCore.this.safeString(market, "amount_precision"))) );
                put( "price", OnetradingCore.this.parseNumber(OnetradingCore.this.parsePrecision(OnetradingCore.this.safeString(market, "market_precision"))) );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", OnetradingCore.this.safeNumber(market, "min_size") );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", market );
        }};
    }

    /**
     * @method
     * @name onetrading#fetchTradingFees
     * @description fetch the trading fees for multiple markets
     * @see https://docs.onetrading.com/rest/public/fee-groups
     * @see https://docs.onetrading.com/rest/trading/fees
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.method] fetchPrivateTradingFees or fetchPublicTradingFees
     * @returns {object} a dictionary of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTradingFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object method = this.safeString(parameters, "method");
            parameters = this.omit(parameters, "method");
            if (Helpers.isTrue(Helpers.isEqual(method, null)))
            {
                Object options = this.safeValue(this.options, "fetchTradingFees", new java.util.HashMap<String, Object>() {{}});
                method = this.safeString(options, "method", "fetchPrivateTradingFees");
            }
            if (Helpers.isTrue(Helpers.isEqual(method, "fetchPrivateTradingFees")))
            {
                return (this.fetchPrivateTradingFees(parameters)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(method, "fetchPublicTradingFees")))
            {
                return (this.fetchPublicTradingFees(parameters)).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchTradingFees() does not support "), method), ", fetchPrivateTradingFees and fetchPublicTradingFees are supported")) ;
            }
        });

    }

    public java.util.concurrent.CompletableFuture<Object> fetchPublicTradingFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.publicGetFees(parameters)).join();
            //
            // [
            //     {
            //         'fee_group_id': 'SPOT',
            //         'display_text': 'The fee plan for spot trading.',
            //         'volume_currency': 'EUR',
            //         'fee_tiers': [
            //             {
            //                 'volume': '0',
            //                 'fee_group_id': 'SPOT',
            //                 'maker_fee': '0.1000',
            //                 'taker_fee': '0.2000',
            //             },
            //             {
            //                 'volume': '10000',
            //                 'fee_group_id': 'SPOT',
            //                 'maker_fee': '0.0400',
            //                 'taker_fee': '0.0800',
            //             },
            //         ],
            //     },
            //     {
            //         'fee_group_id': 'FUTURES',
            //         'display_text': 'The fee plan for futures trading.',
            //         'volume_currency': 'EUR',
            //         'fee_tiers': [
            //             {
            //                 'volume': '0',
            //                 'fee_group_id': 'FUTURES',
            //                 'maker_fee': '0.1000',
            //                 'taker_fee': '0.2000',
            //             },
            //             {
            //                 'volume': '10000',
            //                 'fee_group_id': 'FUTURES',
            //                 'maker_fee': '0.0400',
            //                 'taker_fee': '0.0800',
            //             },
            //         ],
            //     },
            // ];
            //
            Object spotFees = this.safeDict(response, 0, new java.util.HashMap<String, Object>() {{}});
            Object futuresFees = this.safeDict(response, 1, new java.util.HashMap<String, Object>() {{}});
            Object spotFeeTiers = this.safeList(spotFees, "fee_tiers", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object futuresFeeTiers = this.safeList(futuresFees, "fee_tiers", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object spotTiers = this.parseFeeTiers(spotFeeTiers);
            Object futuresTiers = this.parseFeeTiers(futuresFeeTiers);
            Object firstSpotTier = this.safeDict(spotTiers, 0, new java.util.HashMap<String, Object>() {{}});
            Object firstFuturesTier = this.safeDict(futuresTiers, 0, new java.util.HashMap<String, Object>() {{}});
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.symbols)); i++)
            {
                Object symbol = Helpers.GetValue(this.symbols, i);
                Object market = this.market(symbol);
                Object tierObject = ((Helpers.isTrue((Helpers.GetValue(market, "spot"))))) ? firstSpotTier : firstFuturesTier;
                Helpers.addElementToObject(result, symbol, new java.util.HashMap<String, Object>() {{
        put( "info", spotFees );
        put( "symbol", symbol );
        put( "maker", OnetradingCore.this.safeNumber(tierObject, "maker_fee") );
        put( "taker", OnetradingCore.this.safeNumber(tierObject, "taker_fee") );
        put( "percentage", true );
        put( "tierBased", true );
        put( "tiers", spotTiers );
    }});
            }
            return result;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> fetchPrivateTradingFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.privateGetAccountFees(parameters)).join();
            //
            // {
            //    "account_id":"b7f4e27e-b34a-493a-b0d4-4bd341a3f2e0",
            //    "running_volumes":[
            //       {
            //          "fee_group_id":"SPOT",
            //          "volume":"0",
            //          "currency":"EUR"
            //       },
            //       {
            //          "fee_group_id":"FUTURES",
            //          "volume":"0",
            //          "currency":"EUR"
            //       }
            //    ],
            //    "active_fee_tiers":[
            //       {
            //          "fee_group_id":"SPOT",
            //          "volume":"0",
            //          "maker_fee":"0.1000",
            //          "taker_fee":"0.2000"
            //       },
            //       {
            //          "fee_group_id":"FUTURES",
            //          "volume":"0",
            //          "maker_fee":"0.1000",
            //          "taker_fee":"0.2000"
            //       }
            //    ]
            // }
            //
            Object activeFeeTier = this.safeList(response, "active_fee_tiers");
            Object spotFees = this.safeDict(activeFeeTier, 0, new java.util.HashMap<String, Object>() {{}});
            Object futuresFees = this.safeDict(activeFeeTier, 1, new java.util.HashMap<String, Object>() {{}});
            Object spotMakerFee = this.safeString(spotFees, "maker_fee");
            Object spotTakerFee = this.safeString(spotFees, "taker_fee");
            spotMakerFee = Precise.stringDiv(spotMakerFee, "100");
            spotTakerFee = Precise.stringDiv(spotTakerFee, "100");
            // const feeTiers = this.safeValue (response, 'fee_tiers');
            Object futuresMakerFee = this.safeString(futuresFees, "maker_fee");
            Object futuresTakerFee = this.safeString(futuresFees, "taker_fee");
            futuresMakerFee = Precise.stringDiv(futuresMakerFee, "100");
            futuresTakerFee = Precise.stringDiv(futuresTakerFee, "100");
            Object result = new java.util.HashMap<String, Object>() {{}};
            // const tiers = this.parseFeeTiers (feeTiers);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.symbols)); i++)
            {
                Object symbol = Helpers.GetValue(this.symbols, i);
                Object market = this.market(symbol);
                Object makerFee = ((Helpers.isTrue((Helpers.GetValue(market, "spot"))))) ? spotMakerFee : futuresMakerFee;
                Object takerFee = ((Helpers.isTrue((Helpers.GetValue(market, "spot"))))) ? spotTakerFee : futuresTakerFee;
                Helpers.addElementToObject(result, symbol, new java.util.HashMap<String, Object>() {{
        put( "info", response );
        put( "symbol", symbol );
        put( "maker", OnetradingCore.this.parseNumber(makerFee) );
        put( "taker", OnetradingCore.this.parseNumber(takerFee) );
        put( "percentage", true );
        put( "tierBased", true );
        put( "tiers", null );
    }});
            }
            return result;
        });

    }

    public Object parseFeeTiers(Object feeTiers, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object takerFees = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object makerFees = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(feeTiers)); i++)
        {
            Object tier = Helpers.GetValue(feeTiers, i);
            Object volume = this.safeNumber(tier, "volume");
            Object taker = this.safeString(tier, "taker_fee");
            Object maker = this.safeString(tier, "maker_fee");
            maker = Precise.stringDiv(maker, "100");
            taker = Precise.stringDiv(taker, "100");
            ((java.util.List<Object>)makerFees).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(volume, this.parseNumber(maker))));
            ((java.util.List<Object>)takerFees).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(volume, this.parseNumber(taker))));
        }
        return new java.util.HashMap<String, Object>() {{
            put( "maker", makerFees );
            put( "taker", takerFees );
        }};
    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTicker, fetchTickers
        //
        //     {
        //         "instrument_code":"BTC_EUR",
        //         "sequence":602562,
        //         "time":"2020-07-10T06:27:34.951Z",
        //         "state":"ACTIVE",
        //         "is_frozen":0,
        //         "quote_volume":"1695555.1783768",
        //         "base_volume":"205.67436",
        //         "last_price":"8143.91",
        //         "best_bid":"8143.71",
        //         "best_ask":"8156.9",
        //         "price_change":"-147.47",
        //         "price_change_percentage":"-1.78",
        //         "high":"8337.45",
        //         "low":"8110.0"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(ticker, "time"));
        Object marketId = this.safeString(ticker, "instrument_code");
        Object symbol = this.safeSymbol(marketId, market, "_");
        Object last = this.safeString(ticker, "last_price");
        Object percentage = this.safeString(ticker, "price_change_percentage");
        Object change = this.safeString(ticker, "price_change");
        Object baseVolume = this.safeString(ticker, "base_volume");
        Object quoteVolume = this.safeString(ticker, "quote_volume");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", OnetradingCore.this.iso8601(timestamp) );
            put( "high", OnetradingCore.this.safeString(ticker, "high") );
            put( "low", OnetradingCore.this.safeString(ticker, "low") );
            put( "bid", OnetradingCore.this.safeString(ticker, "best_bid") );
            put( "bidVolume", null );
            put( "ask", OnetradingCore.this.safeString(ticker, "best_ask") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", change );
            put( "percentage", percentage );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

